#include<bits/stdc++.h>
using namespace std;
long long n,m;
long long a[500010],T[500010],dp[500010];
struct segment_tree
{
    struct node
    {
        long long l,r,max1;
        long long lson,rson;
        long long tag;
    }a[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].max1=max(a[a[x].lson].max1,a[a[x].rson].max1);
    }
    void pushdown(long long x)
    {
        long long mid=(a[x].l+a[x].r)>>1;
        long long ls=a[x].lson,rs=a[x].rson;
        long long tg=a[x].tag;
        a[ls].max1+=tg;
        a[rs].max1+=tg;
        a[ls].tag+=tg;
        a[rs].tag+=tg;
        a[x].tag=0;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        a[x].tag=0;
        if(l==r)
        {
            a[x].max1=0;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].max1+=z;
            a[x].tag+=z;
            return;
        }
        pushdown(x);
        add(a[x].lson,l,r,z);
        add(a[x].rson,l,r,z);
        pushup(x);
    }
    long long getmax(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return -1e18;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].max1;
        }
        pushdown(x);
        return max(getmax(a[x].lson,l,r),getmax(a[x].rson,l,r));
    }
}t;
long long lst[500010];
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld",&T[i]);
    }
    t.init(0,n);
    for(long long i=1;i<=n;i++)
    {
        if(lst[a[i]])
        {
            t.add(1,lst[a[i]],i-1,T[a[i]]);
        }
        lst[a[i]]=i;
        dp[i]=t.getmax(1,1,n);
        t.add(1,i,i,dp[i]);
    }
    printf("%lld",dp[n]);
    return 0;
}
